package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase() throws NoSuchFieldException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        boolean ignoreHeaderCase = true;

        // When
        CSVFormat result = csvFormat.withIgnoreHeaderCase();

        // Then
        Field ignoreHeaderCaseField = CSVFormat.class.getDeclaredField("ignoreHeaderCase");
        ignoreHeaderCaseField.setAccessible(true);
        boolean resultIgnoreHeaderCase = (boolean) ignoreHeaderCaseField.get(result);
        assertEquals(ignoreHeaderCase, resultIgnoreHeaderCase);
    }
}
